/*---------------------------------------------------------------------------------------------
 *  HIM Inspector Webview Provider
 *  Registers and manages the Inspector View in VS Code
 *--------------------------------------------------------------------------------------------*/

import * as vscode from 'vscode';
import * as fs from 'fs';
import * as path from 'path';
import type { HimInspectorEvent } from './himInspectorService';

export class HimInspectorViewProvider implements vscode.WebviewViewProvider {

	public static readonly viewType = 'himInspector.view';

	private webviewView: vscode.WebviewView | undefined;
	private _eventEmitter = new vscode.EventEmitter<HimInspectorEvent>();

	constructor(
		private readonly extensionUri: vscode.Uri
	) {}

	get onAgentTrace() {
		return this._eventEmitter.event;
	}

	resolveWebviewView(
		webviewView: vscode.WebviewView,
		_context: vscode.WebviewViewResolveContext,
		_token: vscode.CancellationToken
	): void | Thenable<void> {
		this.webviewView = webviewView;

		webviewView.webview.options = {
			enableScripts: true,
			localResourceRoots: [
				vscode.Uri.joinPath(this.extensionUri, 'inspector')
			]
		};

		const htmlPath = vscode.Uri.joinPath(this.extensionUri, 'inspector', 'him-inspector.html');
		webviewView.webview.html = this.loadHtml(htmlPath, webviewView.webview);

		webviewView.webview.onDidReceiveMessage((message: { type: string; data: unknown }) => {
			console.log('[HimInspector] Received message:', message);
		});

		vscode.commands.registerCommand('himInspector.clear', () => {
			this.postMessage({ type: 'clear', data: null });
		});
	}

	private loadHtml(uri: vscode.Uri, webview: vscode.Webview): string {
		try {
			const filePath = uri.fsPath;
			let html = fs.readFileSync(filePath, 'utf8');

			html = html.replace(/(href|src)="([^"]+)"/g, (_match: string, attr: string, src: string) => {
				if (src.startsWith('http') || src.startsWith('data:')) {
					return _match;
				}
				const resourceUri = vscode.Uri.joinPath(this.extensionUri, 'inspector', src);
				const webviewUri = webview.asWebviewUri(resourceUri);
				return `${attr}="${webviewUri}"`;
			});

			return html;
		} catch (e) {
			console.error('[HimInspector] Failed to load HTML:', e);
			return `<html><body style="background:#0a0a0f;color:#00ff88;font-family:monospace;">
				<h1>HIM Inspector</h1>
				<p>Failed to load inspector UI.</p>
			</body></html>`;
		}
	}

	public postMessage(message: { type: string; data: unknown }): void {
		if (this.webviewView) {
			this.webviewView.webview.postMessage(message);
		}
	}

	public emitEvent(event: HimInspectorEvent): void {
		this.postMessage({ type: event.type, data: event.data });
		this._eventEmitter.fire(event);
	}

	public show(): void {
		if (this.webviewView) {
			this.webviewView.show();
		} else {
			vscode.commands.executeCommand('himInspector.view.focus');
		}
	}
}

export class HimInspectorServiceImpl implements vscode.Disposable {
	private _onAgentTrace = new vscode.EventEmitter<HimInspectorEvent>();
	private viewProvider: HimInspectorViewProvider | undefined;

	readonly onAgentTrace = this._onAgentTrace.event;

	setViewProvider(provider: HimInspectorViewProvider): void {
		this.viewProvider = provider;
	}

	startThinking(message?: string): void {
		this.emit({
			type: 'agent_thinking_start',
			data: { timestamp: Date.now(), message }
		});
	}

	startCodeGeneration(language = 'python'): void {
		this.emit({
			type: 'agent_code_start',
			data: { timestamp: Date.now(), language }
		});
	}

	addCodeChunk(line: string, lineNumber: number, totalLines: number, isComplete: boolean): void {
		this.emit({
			type: 'agent_code_chunk',
			data: { line, lineNumber, totalLines, isComplete }
		});
	}

	completeCodeGeneration(totalLines: number, code: string): void {
		this.emit({
			type: 'agent_code_complete',
			data: { timestamp: Date.now(), totalLines, code }
		});
	}

	startExecution(lineNumber: number, lineContent: string): void {
		this.emit({
			type: 'exec_start',
			data: { lineNumber, lineContent, timestamp: Date.now() }
		});
	}

	updateExecution(lineNumber: number, status: 'running' | 'success' | 'error', output?: string, error?: string): void {
		this.emit({
			type: 'exec_line',
			data: { lineNumber, status, output, error }
		});
	}

	completeExecution(duration: number, linesExecuted: number): void {
		this.emit({
			type: 'exec_complete',
			data: { timestamp: Date.now(), duration, linesExecuted }
		});
	}

	reportExecutionError(lineNumber: number, error: string, errorType: string): void {
		this.emit({
			type: 'exec_error',
			data: { lineNumber, error, errorType }
		});
	}

	emitStreamEvent(action: HimInspectorEvent & { type: 'stream_event' }['data'] extends { action: infer A } ? A : never, data: unknown): void {
		this.emit({
			type: 'stream_event',
			data: { action, data, timestamp: Date.now() }
		});
	}

	clear(): void {
		this.emit({
			type: 'clear',
			data: null
		});
	}

	private emit(event: HimInspectorEvent): void {
		this._onAgentTrace.fire(event);
		this.viewProvider?.emitEvent(event);
	}

	dispose(): void {
		this._onAgentTrace.dispose();
	}
}
